import{_ as e,a as o,b as a,c as d,d as i}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as n}from"./chunks/谷歌api秘钥和服务账号截图.C26VSZHd.js";import{_ as r,o as c,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"OCR","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/Other/ocr.md","filePath":"vi-VN/Other/ocr.md","lastUpdated":1781962217000}'),h={name:"vi-VN/Other/ocr.md"};function p(u,t,g,m,b,v){return c(),s("div",null,[...t[0]||(t[0]=[l('<h1 id="ocr" tabindex="-1">OCR <a class="header-anchor" href="#ocr" aria-label="Permalink to &quot;OCR&quot;">​</a></h1><p>OCR trích xuất text từ images, scans và document screenshots.</p><p>Sau recognition, bạn có thể copy result, export thành <code>Markdown</code>, <code>PDF</code> hoặc <code>Word</code>, hoặc package nhiều formats lại để download.</p><h2 id="ocr-lam-đuoc-gi" tabindex="-1">OCR làm được gì <a class="header-anchor" href="#ocr-lam-đuoc-gi" aria-label="Permalink to &quot;OCR làm được gì&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Image text recognition</td><td>Extract text từ images, screenshots và scans.</td></tr><tr><td>Document layout recognition</td><td>Tốt hơn cho tables, formulas, stamps và mixed text-image layouts.</td></tr><tr><td>Multiple services</td><td>Hỗ trợ Baidu PaddleOCR, Microsoft Azure Vision và Google Vision.</td></tr><tr><td>Copy results</td><td>Copy recognized text sau khi processing.</td></tr><tr><td>Export files</td><td>Export <code>Markdown</code>, <code>PDF</code> và <code>Word</code>.</td></tr><tr><td>Batch packaging</td><td>Sau khi recognize nhiều files, download results dưới dạng package.</td></tr></tbody></table><h2 id="cau-hinh-ocr-services-truoc" tabindex="-1">Cấu hình OCR Services trước <a class="header-anchor" href="#cau-hinh-ocr-services-truoc" aria-label="Permalink to &quot;Cấu hình OCR Services trước&quot;">​</a></h2><p>Mở:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; OCR</span></span></code></pre></div><p><img src="'+e+'" alt="IP geolocation and OCR" loading="lazy"></p><p>Điền credentials cho services bạn muốn dùng:</p><table tabindex="0"><thead><tr><th>Service</th><th>What To Enter</th><th>Best For</th></tr></thead><tbody><tr><td>Baidu PaddleOCR</td><td><code>PaddleOCR Token</code></td><td>Recommended first choice. Tốt cho documents, images, tables và mixed layouts.</td></tr><tr><td>Microsoft Azure Vision</td><td><code>Azure Vision Endpoint</code> và <code>Azure Vision API Key</code></td><td>Hữu ích nếu bạn đã dùng Microsoft cloud services.</td></tr><tr><td>Google Vision</td><td><code>Google Vision API Key</code>. Service account <code>JSON</code> chỉ dùng cho quota query.</td><td>Hữu ích nếu bạn dùng Google Cloud services.</td></tr></tbody></table><p>Điền credentials xong thì save.</p><p>Bạn chỉ cần cấu hình một service để test ban đầu. Không cần cả ba.</p><h2 id="google-vision-setup" tabindex="-1">Google Vision Setup <a class="header-anchor" href="#google-vision-setup" aria-label="Permalink to &quot;Google Vision Setup&quot;">​</a></h2><p>Google setup có hai phần:</p><table tabindex="0"><thead><tr><th>Goal</th><th>Requirement</th></tr></thead><tbody><tr><td>Dùng OCR</td><td>Enable <code>Cloud Vision API</code>, rồi tạo <code>API Key</code>.</td></tr><tr><td>Query usage</td><td>Tạo service account, grant <code>Monitoring Viewer</code>, rồi download service account <code>JSON</code>.</td></tr></tbody></table><p><img src="'+n+'" alt="Google API key and service account" loading="lazy"></p><h3 id="dung-google-cho-ocr" tabindex="-1">Dùng Google cho OCR <a class="header-anchor" href="#dung-google-cho-ocr" aria-label="Permalink to &quot;Dùng Google cho OCR&quot;">​</a></h3><ol><li>Mở Google Cloud Console.</li><li>Vào <code>APIs &amp; Services</code>.</li><li>Mở <code>Library</code>, tìm <code>Cloud Vision API</code> và enable.</li><li>Quay lại <code>Credentials</code>.</li><li>Tạo một <code>API Key</code>.</li><li>Mở API Key và copy.</li><li>Paste vào <code>Google Vision API Key</code> trong ImgBed.</li><li>Save.</li></ol><p>Sau đó bạn có thể chọn Google Vision trong OCR dialog.</p><h3 id="query-google-usage" tabindex="-1">Query Google Usage <a class="header-anchor" href="#query-google-usage" aria-label="Permalink to &quot;Query Google Usage&quot;">​</a></h3><p>Quota query không required cho recognition.</p><p>Nó chỉ hiển thị sơ bộ số Google Vision calls đã dùng trong 30 ngày gần nhất.</p><ol><li>Trong Google Cloud Console, mở <code>IAM &amp; Admin</code>.</li><li>Mở <code>Service Accounts</code>.</li><li>Tạo service account, ví dụ <code>vision-monitor</code>.</li><li>Grant role <code>Monitoring Viewer</code>.</li><li>Mở service account details và create key.</li><li>Chọn <code>JSON</code>.</li><li>Download generated JSON file.</li><li>Quay lại ImgBed và import dưới service account <code>JSON</code> (optional).</li><li>Sau khi import thành công, nhấn quota query.</li></ol><p>Sau import, ImgBed hiển thị project name sở hữu service account. Khi query usage, ImgBed đọc Google monitoring data và hiển thị call count của tháng này.</p><p>Tóm lại:</p><table tabindex="0"><thead><tr><th>Item</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Google Vision API Key</code></td><td>Thực hiện OCR recognition.</td></tr><tr><td>Service account <code>JSON</code></td><td>Query số Google Vision calls đã dùng.</td></tr><tr><td><code>Monitoring Viewer</code> role</td><td>Cho phép service account đọc usage data.</td></tr></tbody></table><h2 id="lay-baidu-paddleocr-token" tabindex="-1">Lấy Baidu PaddleOCR Token <a class="header-anchor" href="#lay-baidu-paddleocr-token" aria-label="Permalink to &quot;Lấy Baidu PaddleOCR Token&quot;">​</a></h2><p>Baidu PaddleOCR cần access token.</p><p><img src="'+o+'" alt="Get PaddleOCR token" loading="lazy"></p><p>Mở cửa sổ <code>API</code> call trên trang Baidu PaddleOCR, click để lấy token, rồi copy.</p><p>Quay lại ImgBed, paste vào <code>PaddleOCR Token</code>, rồi save.</p><h2 id="bat-đau-recognition" tabindex="-1">Bắt đầu Recognition <a class="header-anchor" href="#bat-đau-recognition" aria-label="Permalink to &quot;Bắt đầu Recognition&quot;">​</a></h2><p>Trong File Management, chọn image hoặc document screenshot và nhấn <code>OCR</code>.</p><p><img src="'+a+'" alt="OCR recognition" loading="lazy"></p><p>Trong dialog, chọn recognition service và model.</p><p>Common PaddleOCR model choices:</p><table tabindex="0"><thead><tr><th>Model</th><th>Best For</th></tr></thead><tbody><tr><td><code>PP-StructureV3</code></td><td>Recommended default. Tốt cho documents, tables, formulas, stamps và mixed layouts.</td></tr><tr><td><code>PP-OCRv5</code></td><td>Simple images, ordinary text và lightweight recognition.</td></tr><tr><td><code>PaddleOCR-VL</code></td><td>Multilingual, complex images và chart-like content.</td></tr><tr><td><code>PaddleOCR-VL-1.5</code></td><td>Document pages phức tạp hơn và layout recovery.</td></tr></tbody></table><p>Nếu chưa chắc, bắt đầu với <code>PP-StructureV3</code>.</p><h2 id="advanced-options" tabindex="-1">Advanced Options <a class="header-anchor" href="#advanced-options" aria-label="Permalink to &quot;Advanced Options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>Orientation correction</td><td>Dùng khi image bị xoay hoặc nghiêng.</td></tr><tr><td>Document flattening</td><td>Dùng cho photographed documents có cong hoặc nghiêng.</td></tr><tr><td>Layout detection</td><td>Dùng khi muốn preserve headings, paragraphs, tables và image structure.</td></tr><tr><td>Chart recognition</td><td>Dùng khi image có charts hoặc structures phức tạp.</td></tr><tr><td>Beautify <code>Markdown</code></td><td>Làm exported Markdown dễ đọc hơn.</td></tr></tbody></table><p>Với regular screenshots, giữ options tối giản. Với document scans, bật thêm document-related options.</p><h2 id="xem-results" tabindex="-1">Xem Results <a class="header-anchor" href="#xem-results" aria-label="Permalink to &quot;Xem Results&quot;">​</a></h2><p>Sau khi recognition xong, dialog hiển thị result.</p><p>Bạn có thể copy trực tiếp hoặc chọn export formats.</p><p><img src="'+d+'" alt="PDF recognition" loading="lazy"></p><p>Với document pages, exported <code>PDF</code> có thể preserve page appearance và vẫn giữ text searchable. Điều này hữu ích để archive scans và tìm content sau này.</p><h2 id="chon-export-format" tabindex="-1">Chọn Export Format <a class="header-anchor" href="#chon-export-format" aria-label="Permalink to &quot;Chọn Export Format&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Best For</th></tr></thead><tbody><tr><td><code>Markdown (.md)</code></td><td>Notes, documentation systems và chỉnh sửa sau này.</td></tr><tr><td><code>PDF (.pdf)</code></td><td>Preserve page appearance và scanned document results.</td></tr><tr><td><code>Word (.docx)</code></td><td>Layout editing, text modification và handoff cho người khác.</td></tr><tr><td>Export all</td><td>Save nhiều formats và original image, phù hợp với archives quan trọng.</td></tr></tbody></table><p>Nếu chỉ cần text, export Markdown.</p><p>Nếu cần page appearance, dùng PDF hoặc Word.</p><h2 id="word-output" tabindex="-1">Word Output <a class="header-anchor" href="#word-output" aria-label="Permalink to &quot;Word Output&quot;">​</a></h2><p>Exported Word documents có thể mở và edit bằng office software.</p><p><img src="'+i+`" alt="Word result" loading="lazy"></p><p>Một số documents có recognized images, headings và paragraphs trong Word output.</p><p>Recognition quality phụ thuộc vào original image clarity, model choice và document complexity.</p><h2 id="file-types-phu-hop-voi-ocr" tabindex="-1">File Types phù hợp với OCR <a class="header-anchor" href="#file-types-phu-hop-voi-ocr" aria-label="Permalink to &quot;File Types phù hợp với OCR&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File Type</th><th>Recommendation</th></tr></thead><tbody><tr><td>Clear screenshots</td><td>Recognize trực tiếp.</td></tr><tr><td>Scans</td><td>Ưu tiên <code>PP-StructureV3</code>.</td></tr><tr><td>Photographed documents</td><td>Enable orientation correction và document flattening.</td></tr><tr><td>Tables, formulas, stamps</td><td>Ưu tiên structured models.</td></tr><tr><td>Simple short text images</td><td><code>PP-OCRv5</code> thường đủ.</td></tr></tbody></table><p>Images càng rõ và text càng thẳng thì results thường càng tốt.</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Recognition fails</td><td>Kiểm tra service token hoặc key đã save chưa.</td></tr><tr><td>Recognition slow</td><td>Complex documents và large images mất thời gian hơn.</td></tr><tr><td>Table incomplete</td><td>Thử structured model.</td></tr><tr><td>Text có lỗi</td><td>Blur, glare và skew làm tăng recognition errors. Thử image rõ hơn.</td></tr><tr><td>Word output có nhiều images</td><td>Structured models có thể preserve một số recognized images. Đây là bình thường.</td></tr></tbody></table><h3 id="google-quota-query-fails" tabindex="-1">Google Quota Query Fails <a class="header-anchor" href="#google-quota-query-fails" aria-label="Permalink to &quot;Google Quota Query Fails&quot;">​</a></h3><p>Kiểm tra:</p><ol><li>Service account <code>JSON</code> đã được import.</li><li>Service account có role <code>Monitoring Viewer</code>.</li><li><code>Cloud Vision API</code> đã enabled cho project.</li></ol><p>Nếu chỉ cần OCR và không cần usage query, có thể bỏ qua service account JSON và chỉ điền <code>Google Vision API Key</code>.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Mở System Settings</span></span>
<span class="line"><span>-&gt; Mở Other Settings</span></span>
<span class="line"><span>-&gt; Điền OCR service credentials</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; Quay lại File Management</span></span>
<span class="line"><span>-&gt; Chọn file và nhấn OCR</span></span>
<span class="line"><span>-&gt; Chọn model</span></span>
<span class="line"><span>-&gt; Chờ recognition</span></span>
<span class="line"><span>-&gt; Copy results hoặc export Markdown / PDF / Word</span></span></code></pre></div>`,67)])])}const k=r(h,[["render",p]]);export{P as __pageData,k as default};
